/**
 * Form Builder Plugin Types
 *
 * Key distinction from CMS Plugin:
 * - CMS uses developer-defined Zod schemas in code
 * - Form Builder allows non-technical admins to build forms via drag-and-drop UI
 * - Forms are serialized to/from JSON Schema for storage
 */

/**
 * Form stored in the database
 */
export type Form = {
	id: string;
	/** Display name for the form */
	name: string;
	/** URL-friendly slug - unique identifier for public access */
	slug: string;
	/** Optional description for admin UI */
	description?: string;
	/** JSON Schema stored as string (includes steps, fieldType, stepGroup, etc.) */
	schema: string;
	/** Optional custom success message after submission */
	successMessage?: string;
	/** Optional redirect URL after submission */
	redirectUrl?: string;
	/** Form status: active, inactive, archived */
	status: "active" | "inactive" | "archived";
	/** User who created the form */
	createdBy?: string;
	createdAt: Date;
	updatedAt: Date;
};

/**
 * Form submission stored in the database
 */
export type FormSubmission = {
	id: string;
	/** Reference to the form */
	formId: string;
	/** Submitted data as JSON string */
	data: string;
	/** Submission timestamp */
	submittedAt: Date;
	/** Optional user ID if authenticated */
	submittedBy?: string;
	/** Client IP address for rate limiting and spam protection */
	ipAddress?: string;
	/** User agent for analytics */
	userAgent?: string;
};

/**
 * Form submission with its parent form joined
 */
export type FormSubmissionWithForm = FormSubmission & {
	form?: Form;
};

/**
 * Serialized form for API responses (dates as strings)
 */
export interface SerializedForm
	extends Omit<Form, "createdAt" | "updatedAt" | "status"> {
	status: string;
	createdAt: string;
	updatedAt: string;
}

/**
 * Serialized form submission for API responses (dates as strings)
 */
export interface SerializedFormSubmission
	extends Omit<FormSubmission, "submittedAt"> {
	submittedAt: string;
}

/**
 * Serialized form submission with parsed data
 */
export interface SerializedFormSubmissionWithData<
	TData = Record<string, unknown>,
> extends SerializedFormSubmission {
	/** Parsed data object (JSON.parse of data field). Null when the stored JSON is corrupted. */
	parsedData: TData | null;
	/** Joined form */
	form?: SerializedForm;
}

/**
 * Paginated list response for forms
 */
export interface PaginatedForms {
	items: SerializedForm[];
	total: number;
	limit: number;
	offset: number;
}

/**
 * Paginated list response for form submissions
 */
export interface PaginatedFormSubmissions<TData = Record<string, unknown>> {
	items: SerializedFormSubmissionWithData<TData>[];
	total: number;
	limit: number;
	offset: number;
}

// ============================================================================
// BACKEND HOOKS
// ============================================================================

/**
 * Context passed to all backend hooks
 */
export interface FormBuilderHookContext {
	/** User ID if authenticated */
	userId?: string;
	/** Request headers */
	headers?: Headers;
	/** Client IP address (for rate limiting) */
	ipAddress?: string;
	/** User agent string */
	userAgent?: string;
}

/**
 * Context for submission-specific hooks
 */
export interface SubmissionHookContext extends FormBuilderHookContext {
	/** Form slug being submitted */
	formSlug: string;
	/** Form ID */
	formId: string;
}

/**
 * Input data for creating a form
 */
export interface FormInput {
	name: string;
	slug: string;
	description?: string;
	schema: string;
	successMessage?: string;
	redirectUrl?: string;
	status?: "active" | "inactive" | "archived";
	createdBy?: string;
}

/**
 * Input data for updating a form
 */
export interface FormUpdate {
	name?: string;
	slug?: string;
	description?: string;
	schema?: string;
	successMessage?: string;
	redirectUrl?: string;
	status?: "active" | "inactive" | "archived";
}

/**
 * Backend hooks for Form Builder plugin
 *
 * All CRUD hooks receive ipAddress and headers for auth/rate limiting.
 * Throw an error from onBefore* hooks to reject the operation (throws 403).
 */
export interface FormBuilderBackendHooks {
	// ============================================================================
	// FORM CRUD HOOKS (Admin operations)
	// ============================================================================

	/** Called before listing forms. Throw an error to deny access (403). */
	onBeforeListForms?: (ctx: FormBuilderHookContext) => Promise<void> | void;

	/** Called before creating a form. Throw an error to deny, or return modified data. */
	onBeforeFormCreated?: (
		data: FormInput,
		ctx: FormBuilderHookContext,
	) => Promise<FormInput | void> | FormInput | void;

	/** Called after a form is created */
	onAfterFormCreated?: (
		form: SerializedForm,
		ctx: FormBuilderHookContext,
	) => Promise<void> | void;

	/** Called before getting a form by ID or slug. Throw an error to deny access. */
	onBeforeGetForm?: (
		idOrSlug: string,
		ctx: FormBuilderHookContext,
	) => Promise<void> | void;

	/** Called before updating a form. Throw an error to deny, or return modified data. */
	onBeforeFormUpdated?: (
		id: string,
		data: FormUpdate,
		ctx: FormBuilderHookContext,
	) => Promise<FormUpdate | void> | FormUpdate | void;

	/** Called after a form is updated */
	onAfterFormUpdated?: (
		form: SerializedForm,
		ctx: FormBuilderHookContext,
	) => Promise<void> | void;

	/** Called before deleting a form. Throw an error to deny. */
	onBeforeFormDeleted?: (
		id: string,
		ctx: FormBuilderHookContext,
	) => Promise<void> | void;

	/** Called after a form is deleted */
	onAfterFormDeleted?: (
		id: string,
		ctx: FormBuilderHookContext,
	) => Promise<void> | void;

	// ============================================================================
	// SUBMISSION HOOKS (Public form submissions)
	// ============================================================================

	/**
	 * Called before processing a form submission.
	 * Use for: spam protection, rate limiting, data validation/enrichment.
	 *
	 * Throw an error to reject submission (400), or return modified data to continue.
	 */
	onBeforeSubmission?: (
		formSlug: string,
		data: Record<string, unknown>,
		ctx: SubmissionHookContext,
	) => Promise<Record<string, unknown> | void> | Record<string, unknown> | void;

	/**
	 * Called after a submission is saved.
	 * Use for: sending emails, storing in CRM, triggering workflows.
	 */
	onAfterSubmission?: (
		submission: SerializedFormSubmission,
		form: SerializedForm,
		ctx: SubmissionHookContext,
	) => Promise<void> | void;

	/** Called when a submission fails */
	onSubmissionError?: (
		error: Error,
		formSlug: string,
		data: Record<string, unknown>,
		ctx: SubmissionHookContext,
	) => Promise<void> | void;

	// ============================================================================
	// SUBMISSIONS MANAGEMENT HOOKS (Admin viewing submissions)
	// ============================================================================

	/** Called before listing submissions. Throw an error to deny access (403). */
	onBeforeListSubmissions?: (
		formId: string,
		ctx: FormBuilderHookContext,
	) => Promise<void> | void;

	/** Called before getting a submission. Throw an error to deny access. */
	onBeforeGetSubmission?: (
		submissionId: string,
		ctx: FormBuilderHookContext,
	) => Promise<void> | void;

	/** Called before deleting a submission. Throw an error to deny. */
	onBeforeSubmissionDeleted?: (
		submissionId: string,
		ctx: FormBuilderHookContext,
	) => Promise<void> | void;

	/** Called after a submission is deleted */
	onAfterSubmissionDeleted?: (
		submissionId: string,
		ctx: FormBuilderHookContext,
	) => Promise<void> | void;

	// ============================================================================
	// ERROR HOOK
	// ============================================================================

	/** Called on any error */
	onError?: (
		error: Error,
		operation:
			| "list"
			| "get"
			| "create"
			| "update"
			| "delete"
			| "submit"
			| "listSubmissions"
			| "getSubmission"
			| "deleteSubmission",
		ctx: FormBuilderHookContext,
	) => Promise<void> | void;
}

/**
 * Configuration for the Form Builder backend plugin
 */
export interface FormBuilderBackendConfig {
	/** Optional hooks for customizing behavior */
	hooks?: FormBuilderBackendHooks;
}

import { z } from "zod";

/**
 * Schema for listing forms with pagination
 */
export const listFormsQuerySchema = z.object({
	status: z.enum(["active", "inactive", "archived"]).optional(),
	limit: z.coerce.number().min(1).max(100).optional().default(20),
	offset: z.coerce.number().min(0).optional().default(0),
});

/**
 * Schema for creating a form
 */
export const createFormSchema = z.object({
	name: z.string().min(1, "Name is required"),
	slug: z.string().min(1, "Slug is required"),
	description: z.string().optional(),
	schema: z.string().min(1, "Schema is required"),
	successMessage: z.string().optional(),
	redirectUrl: z.string().url().optional().or(z.literal("")),
	status: z
		.enum(["active", "inactive", "archived"])
		.optional()
		.default("active"),
});

/**
 * Schema for updating a form
 */
export const updateFormSchema = z.object({
	name: z.string().min(1, "Name is required").optional(),
	slug: z.string().min(1, "Slug is required").optional(),
	description: z.string().optional(),
	schema: z.string().min(1, "Schema is required").optional(),
	successMessage: z.string().optional(),
	redirectUrl: z.string().url().optional().or(z.literal("")),
	status: z.enum(["active", "inactive", "archived"]).optional(),
});

/**
 * Schema for form response
 */
export const formResponseSchema = z.object({
	id: z.string(),
	name: z.string(),
	slug: z.string(),
	description: z.string().nullable().optional(),
	schema: z.string(),
	successMessage: z.string().nullable().optional(),
	redirectUrl: z.string().nullable().optional(),
	status: z.string(),
	createdBy: z.string().nullable().optional(),
	createdAt: z.string(),
	updatedAt: z.string(),
});

/**
 * Schema for paginated forms response
 */
export const paginatedFormsResponseSchema = z.object({
	items: z.array(formResponseSchema),
	total: z.number(),
	limit: z.number(),
	offset: z.number(),
});

/**
 * Schema for listing form submissions with pagination
 */
export const listSubmissionsQuerySchema = z.object({
	limit: z.coerce.number().min(1).max(100).optional().default(20),
	offset: z.coerce.number().min(0).optional().default(0),
});

/**
 * Schema for submitting a form (public)
 */
export const submitFormSchema = z.object({
	// Use passthrough object for dynamic form data validation
	data: z.object({}).passthrough(),
});

/**
 * Schema for form submission response
 */
export const formSubmissionResponseSchema = z.object({
	id: z.string(),
	formId: z.string(),
	data: z.string(),
	submittedAt: z.string(),
	submittedBy: z.string().nullable().optional(),
	ipAddress: z.string().nullable().optional(),
	userAgent: z.string().nullable().optional(),
});

/**
 * Schema for form submission with parsed data response
 */
export const formSubmissionWithDataResponseSchema =
	formSubmissionResponseSchema.extend({
		// Use passthrough object for dynamic parsed data
		parsedData: z.object({}).passthrough(),
		form: formResponseSchema.optional(),
	});

/**
 * Schema for paginated submissions response
 */
export const paginatedSubmissionsResponseSchema = z.object({
	items: z.array(formSubmissionWithDataResponseSchema),
	total: z.number(),
	limit: z.number(),
	offset: z.number(),
});

// Export inferred types
export type ListFormsQuery = z.infer<typeof listFormsQuerySchema>;
export type CreateFormInput = z.infer<typeof createFormSchema>;
export type UpdateFormInput = z.infer<typeof updateFormSchema>;
export type ListSubmissionsQuery = z.infer<typeof listSubmissionsQuerySchema>;
export type SubmitFormInput = z.infer<typeof submitFormSchema>;

import { clsx, type ClassValue } from "clsx";
import { twMerge } from "tailwind-merge";
import slug from "slug";

/**
 * Converts text to a URL-friendly slug
 */
export function slugify(text: string, locale: string = "en"): string {
	return slug(text, { lower: true, locale });
}

/**
 * Merges class names using clsx and tailwind-merge
 */
export function cn(...inputs: ClassValue[]) {
	return twMerge(clsx(inputs));
}

/**
 * Safely parses JSON with a fallback
 */
export function safeJsonParse<T>(json: string, fallback: T): T {
	try {
		return JSON.parse(json) as T;
	} catch {
		return fallback;
	}
}

/**
 * Extracts client IP address from request headers
 * Handles common proxy headers
 */
export function extractIpAddress(headers?: Headers): string | undefined {
	if (!headers) return undefined;

	// Check common proxy headers in order of preference
	const forwardedFor = headers.get("x-forwarded-for");
	if (forwardedFor) {
		// x-forwarded-for can contain multiple IPs, take the first one
		return forwardedFor.split(",")[0]?.trim();
	}

	const realIp = headers.get("x-real-ip");
	if (realIp) {
		return realIp.trim();
	}

	const cfConnectingIp = headers.get("cf-connecting-ip");
	if (cfConnectingIp) {
		return cfConnectingIp.trim();
	}

	return undefined;
}

/**
 * Extracts user agent from request headers
 */
export function extractUserAgent(headers?: Headers): string | undefined {
	if (!headers) return undefined;
	return headers.get("user-agent") || undefined;
}

"use client";

import { useState, useMemo, type ComponentType } from "react";
import { usePluginOverrides } from "@btst/stack/context";
import { SteppedAutoForm } from "@/components/ui/auto-form/stepped-auto-form";
import { buildFieldConfigFromJsonSchema } from "@/components/ui/auto-form/helpers";
import { formSchemaToZod } from "@/lib/schema-converter";
import { Skeleton } from "@/components/ui/skeleton";
import { AlertCircle, CheckCircle } from "lucide-react";
import type { AutoFormInputComponentProps } from "@/components/ui/auto-form/types";

import { useFormBySlug, useSubmitForm } from "@btst/stack/plugins/form-builder/client/hooks";
import type { FormBuilderPluginOverrides } from "../../overrides";
import { FORM_BUILDER_LOCALIZATION } from "../../localization";
import type { SerializedFormSubmission } from "../../../types";

export interface FormRendererProps {
	/** Form slug to render */
	slug: string;
	/** Callback when form submission succeeds */
	onSuccess?: (
		submission: SerializedFormSubmission & {
			form: { successMessage?: string; redirectUrl?: string };
		},
	) => void;
	/** Callback when form submission fails */
	onError?: (error: Error) => void;
	/** Custom field components (same as FormBuilder) */
	fieldComponents?: Record<string, ComponentType<AutoFormInputComponentProps>>;
	/** Override success message */
	successMessage?: React.ReactNode;
	/** Override submit button text */
	submitButtonText?: string;
	/** Custom loading component */
	LoadingComponent?: ComponentType;
	/** Custom error component */
	ErrorComponent?: ComponentType<{ error: Error }>;
	/** Class name for the form container */
	className?: string;
}

function DefaultLoadingComponent() {
	return (
		<div className="space-y-4">
			<Skeleton className="h-10 w-full" />
			<Skeleton className="h-10 w-full" />
			<Skeleton className="h-10 w-full" />
			<Skeleton className="h-10 w-32" />
		</div>
	);
}

function DefaultErrorComponent({ error }: { error: Error }) {
	return (
		<div className="flex flex-col items-center justify-center py-8 text-center">
			<div className="rounded-full bg-destructive/10 p-3 mb-4">
				<AlertCircle className="h-6 w-6 text-destructive" />
			</div>
			<h3 className="text-lg font-medium text-foreground mb-2">
				Failed to load form
			</h3>
			<p className="text-sm text-muted-foreground max-w-sm">
				{error.message || "An unexpected error occurred"}
			</p>
		</div>
	);
}

function DefaultSuccessComponent({ message }: { message: React.ReactNode }) {
	return (
		<div className="flex flex-col items-center justify-center py-8 text-center">
			<div className="rounded-full bg-green-100 dark:bg-green-900 p-3 mb-4">
				<CheckCircle className="h-6 w-6 text-green-600 dark:text-green-400" />
			</div>
			<h3 className="text-lg font-medium text-foreground mb-2">
				Form Submitted
			</h3>
			<p className="text-sm text-muted-foreground max-w-sm">{message}</p>
		</div>
	);
}

/**
 * FormRenderer component for rendering forms on the frontend.
 *
 * Uses SteppedAutoForm which automatically handles both single-step and multi-step forms.
 *
 * @example
 * ```tsx
 * <FormRenderer
 *   slug="contact-form"
 *   onSuccess={() => {
 *     toast.success("Thank you!");
 *   }}
 *   onError={(error) => {
 *     toast.error("Something went wrong");
 *   }}
 * />
 * ```
 */
export function FormRenderer({
	slug,
	onSuccess,
	onError,
	fieldComponents: propFieldComponents,
	successMessage: propSuccessMessage,
	submitButtonText,
	LoadingComponent = DefaultLoadingComponent,
	ErrorComponent = DefaultErrorComponent,
	className,
}: FormRendererProps) {
	const { fieldComponents: overrideFieldComponents, localization } =
		usePluginOverrides<
			FormBuilderPluginOverrides,
			Partial<FormBuilderPluginOverrides>
		>("form-builder", {
			localization: FORM_BUILDER_LOCALIZATION,
		});

	const loc = localization || FORM_BUILDER_LOCALIZATION;

	const { form, isLoading, error } = useFormBySlug(slug);
	const submitMutation = useSubmitForm(slug);

	const [submitted, setSubmitted] = useState(false);
	const [finalSuccessMessage, setFinalSuccessMessage] = useState<string | null>(
		null,
	);

	// Merge field components from props and overrides
	const mergedFieldComponents = useMemo(
		() => ({
			...overrideFieldComponents,
			...propFieldComponents,
		}),
		[overrideFieldComponents, propFieldComponents],
	);

	// Parse JSON Schema and create Zod schema
	const { zodSchema, fieldConfig } = useMemo(() => {
		if (!form?.schema) {
			return { zodSchema: null, fieldConfig: {} };
		}

		try {
			const parsedSchema = JSON.parse(form.schema);
			const zod = formSchemaToZod(parsedSchema);
			const config = buildFieldConfigFromJsonSchema(
				parsedSchema,
				mergedFieldComponents,
			);

			return { zodSchema: zod, fieldConfig: config };
		} catch {
			return { zodSchema: null, fieldConfig: {} };
		}
	}, [form?.schema, mergedFieldComponents]);

	const handleSubmit = async (data: Record<string, unknown>) => {
		try {
			const result = await submitMutation.mutateAsync({ data });

			// Set success message
			const message =
				propSuccessMessage ||
				result.form.successMessage ||
				"Thank you for your submission!";
			setFinalSuccessMessage(message as string);
			setSubmitted(true);

			// Call onSuccess callback before any redirect
			onSuccess?.(result);

			// Handle redirect
			if (result.form.redirectUrl) {
				window.location.href = result.form.redirectUrl;
				return;
			}
		} catch (err) {
			onError?.(err as Error);
		}
	};

	// Loading state
	if (isLoading) {
		return (
			<div className={className}>
				<LoadingComponent />
			</div>
		);
	}

	// Error state
	if (error) {
		return (
			<div className={className}>
				<ErrorComponent error={error} />
			</div>
		);
	}

	// Form not found
	if (!form) {
		return (
			<div className={className}>
				<ErrorComponent error={new Error("Form not found")} />
			</div>
		);
	}

	// Form not active
	if (form.status !== "active") {
		return (
			<div className={className}>
				<ErrorComponent
					error={new Error("This form is not currently accepting submissions")}
				/>
			</div>
		);
	}

	// Schema parsing failed
	if (!zodSchema) {
		return (
			<div className={className}>
				<ErrorComponent error={new Error("Failed to parse form schema")} />
			</div>
		);
	}

	// Success state
	if (submitted && finalSuccessMessage) {
		return (
			<div className={className}>
				<DefaultSuccessComponent message={finalSuccessMessage} />
			</div>
		);
	}

	// Render form using SteppedAutoForm
	// It automatically handles both single-step and multi-step forms
	return (
		<div className={className} data-testid="form-renderer">
			<SteppedAutoForm
				formSchema={zodSchema}
				fieldConfig={fieldConfig}
				onSubmit={(values) => handleSubmit(values as Record<string, unknown>)}
				isSubmitting={submitMutation.isPending}
				submitButtonText={submitButtonText || loc.FORM_BUILDER_BUTTON_SUBMIT}
			/>
		</div>
	);
}

"use client";

