"use client";

import { useState } from "react";
import { usePluginOverrides, useBasePath } from "@btst/stack/context";
import { Button } from "@/components/ui/button";
import {
	Table,
	TableBody,
	TableCell,
	TableHead,
	TableHeader,
	TableRow,
} from "@/components/ui/table";
import {
	DropdownMenu,
	DropdownMenuContent,
	DropdownMenuItem,
	DropdownMenuTrigger,
} from "@/components/ui/dropdown-menu";
import {
	AlertDialog,
	AlertDialogAction,
	AlertDialogCancel,
	AlertDialogContent,
	AlertDialogDescription,
	AlertDialogFooter,
	AlertDialogHeader,
	AlertDialogTitle,
} from "@/components/ui/alert-dialog";
import { MoreHorizontal, Plus, Pencil, Trash2, FileText } from "lucide-react";
import { toast } from "sonner";

import {
	useSuspenseForms,
	useDeleteForm,
} from "@btst/stack/plugins/form-builder/client/hooks";
import type { FormBuilderPluginOverrides } from "../../overrides";
import { FORM_BUILDER_LOCALIZATION } from "../../localization";
import { PageWrapper } from "../shared/page-wrapper";
import { EmptyState } from "../shared/empty-state";
