import React, { useState, useMemo, useCallback, useRef, useEffect } from "react";
import { z } from "zod";
import type { UseFormReturn } from "react-hook-form";
import AutoForm from "./index";
import { Button } from "@/components/ui/button";
import { Separator } from "@/components/ui/separator";
import { cn } from "@/lib/utils";
import type { FieldConfig } from "./types";
import type { ZodObjectOrWrapped } from "./helpers";

export default SteppedAutoForm;
export { SteppedAutoForm };
export type { SteppedAutoFormProps, StepperComponentProps };

// ============================================================================
// TYPES
// ============================================================================

interface FormStep {
  id: string;
  title: string;
}

interface StepperComponentProps {
  steps: Array<{ id: string; label: string }>;
  currentStepIndex: number;
  currentStepId: string;
  onStepClick?: (stepId: string) => void;
  isFirst: boolean;
  isLast: boolean;
}

interface SteppedAutoFormProps<SchemaType extends ZodObjectOrWrapped> {
  // Same props as AutoForm
  formSchema: SchemaType;
  values?: Partial<z.infer<SchemaType>>;
  onValuesChange?: (
    values: Partial<z.infer<SchemaType>>,
    form?: UseFormReturn<z.infer<SchemaType>>
  ) => void;
  onSubmit?: (values: z.infer<SchemaType>) => void;
  fieldConfig?: FieldConfig<z.infer<SchemaType>>;
  children?: React.ReactNode;
  className?: string;

  // Stepper customization
  nextButtonText?: string;
  backButtonText?: string;
  submitButtonText?: string;
  StepperComponent?: React.ComponentType<StepperComponentProps>;

  /** Whether the form is currently submitting. Disables submit/next buttons to prevent duplicate submissions. */
  isSubmitting?: boolean;
}

// ============================================================================
// HELPER FUNCTIONS
// ============================================================================

/**
 * Extract steps from a Zod schema's JSON Schema representation.
 * Steps are stored in the schema's .meta() and serialized to JSON Schema.
 */
function extractStepsFromSchema(schema: z.ZodType): FormStep[] {
  try {
    const jsonSchema = schema.toJSONSchema() as Record<string, unknown>;
    // Steps are added via .meta({ steps }) and serialized at root level
    if (jsonSchema.steps && Array.isArray(jsonSchema.steps)) {
      return jsonSchema.steps as FormStep[];
    }
  } catch {
    // Schema doesn't support toJSONSchema or doesn't have steps
  }
  return [];
}

/**
 * Get field names and their step assignments from JSON Schema.
 * We check both the stepGroupMap from meta and individual field stepGroup properties.
 */
function getFieldStepAssignments(
  schema: z.ZodType
): Map<string, number> {
  const assignments = new Map<string, number>();
  try {
    const jsonSchema = schema.toJSONSchema() as Record<string, unknown>;

    // First, check for stepGroupMap in meta (added when converting from JSON Schema)
    const stepGroupMap = jsonSchema.stepGroupMap as Record<string, number> | undefined;
    if (stepGroupMap) {
      for (const [fieldName, stepGroup] of Object.entries(stepGroupMap)) {
        assignments.set(fieldName, stepGroup);
      }
      return assignments;
    }

    // Fallback: check individual field properties for stepGroup
    const properties = jsonSchema.properties as Record<string, Record<string, unknown>> | undefined;
    if (properties) {
      for (const [fieldName, fieldSchema] of Object.entries(properties)) {
        const stepGroup = fieldSchema.stepGroup;
        if (typeof stepGroup === "number") {
          assignments.set(fieldName, stepGroup);
        } else {
          // Default to step 0 if not specified
          assignments.set(fieldName, 0);
        }
      }
    }
  } catch {
    // Schema doesn't support toJSONSchema
  }
  return assignments;
}

/**
 * Create a partial schema for a specific step by picking only fields that belong to that step
 */
function createStepSchema<T extends z.ZodObject<z.ZodRawShape>>(
  fullSchema: T,
  stepIndex: number,
  fieldAssignments: Map<string, number>
): z.ZodObject<z.ZodRawShape> {
  const fieldsForStep = Array.from(fieldAssignments.entries())
    .filter(([, step]) => step === stepIndex)
    .map(([field]) => field);

  if (fieldsForStep.length === 0) {
    // Return empty object schema if no fields
    return z.object({});
  }

  // Create pick object
  const pickObject: Record<string, true> = {};
  for (const field of fieldsForStep) {
    pickObject[field] = true;
  }

  return fullSchema.pick(pickObject) as z.ZodObject<z.ZodRawShape>;
}

/**
 * Get the inner schema from wrapped Zod types (effects, optional, etc.)
 * In Zod v4, we use duck typing to detect schema types
 */
function getObjectSchema(schema: z.ZodType): z.ZodObject<z.ZodRawShape> | null {
  // Check if it's a ZodObject by checking for shape property
  if (schema instanceof z.ZodObject) {
    return schema as z.ZodObject<z.ZodRawShape>;
  }

  // For wrapped types (effects, optional, nullable), try to access inner schema
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  const schemaDef = (schema as any)._zod?.def ?? (schema as any)._def;
  if (schemaDef) {
    // ZodEffects has schema property
    if (schemaDef.schema) {
      return getObjectSchema(schemaDef.schema);
    }
    // ZodOptional/ZodNullable have innerType
    if (schemaDef.innerType) {
      return getObjectSchema(schemaDef.innerType);
    }
  }

  return null;
}

// ============================================================================
// DEFAULT STEPPER COMPONENT
// ============================================================================

function DefaultStepper({
  steps,
  currentStepIndex,
  onStepClick,
}: StepperComponentProps) {
  return (
    <nav aria-label="Form Steps" className="mb-6">
      <ol className="flex items-center justify-between gap-2">
        {steps.map((step, index) => (
          <React.Fragment key={step.id}>
            <li className="flex items-center gap-2 shrink-0">
              <Button
                type="button"
                variant={index <= currentStepIndex ? "default" : "secondary"}
                aria-current={currentStepIndex === index ? "step" : undefined}
                aria-posinset={index + 1}
                aria-setsize={steps.length}
                className="size-10 rounded-full p-0"
                onClick={() => onStepClick?.(step.id)}
              >
                {index + 1}
              </Button>
              <span className="text-sm font-medium hidden sm:inline">
                {step.label}
              </span>
            </li>
            {index < steps.length - 1 && (
              <Separator
                className={cn(
                  "flex-1 min-w-4",
                  index < currentStepIndex ? "bg-primary" : "bg-muted"
                )}
              />
            )}
          </React.Fragment>
        ))}
      </ol>
    </nav>
  );
}

// ============================================================================
// STEPPED AUTO FORM COMPONENT
// ============================================================================

function SteppedAutoForm<SchemaType extends ZodObjectOrWrapped>({
  formSchema,
  values: initialValues,
  onValuesChange,
  onSubmit,
  fieldConfig,
  children,
  className,
  nextButtonText = "Next",
  backButtonText = "Back",
  submitButtonText = "Submit",
  StepperComponent = DefaultStepper,
  isSubmitting = false,
}: SteppedAutoFormProps<SchemaType>) {
  // Extract steps from schema
  const steps = useMemo(() => extractStepsFromSchema(formSchema), [formSchema]);
  const hasMultipleSteps = steps.length > 1;

  // Get field assignments
  const fieldAssignments = useMemo(
    () => getFieldStepAssignments(formSchema),
    [formSchema]
  );

  // State for multi-step form
  const [currentStepIndex, setCurrentStepIndex] = useState(0);
  const [accumulatedValues, setAccumulatedValues] = useState<Record<string, unknown>>(
    (initialValues as Record<string, unknown>) ?? {}
  );
  // Track which steps have been validated/completed (by step index)
  const [completedSteps, setCompletedSteps] = useState<Set<number>>(new Set());
  // Track schema validation errors (for cross-field validations)
  const [schemaErrors, setSchemaErrors] = useState<z.ZodError | null>(null);

  // Refs to avoid stale closures in callbacks - ensures we always have latest values
  const accumulatedValuesRef = useRef(accumulatedValues);
  const onValuesChangeRef = useRef(onValuesChange);

  // Keep refs in sync with current values
  useEffect(() => {
    accumulatedValuesRef.current = accumulatedValues;
  }, [accumulatedValues]);

  useEffect(() => {
    onValuesChangeRef.current = onValuesChange;
  }, [onValuesChange]);

  // Sync accumulated values when the values prop changes externally
  // This handles async loading scenarios where data arrives after mount
  useEffect(() => {
    if (initialValues) {
      const newValues = {
        ...accumulatedValuesRef.current,
        ...(initialValues as Record<string, unknown>),
      };
      accumulatedValuesRef.current = newValues;
      setAccumulatedValues(newValues);
    }
  }, [initialValues]);

  // Get the object schema
  const objectSchema = useMemo(() => getObjectSchema(formSchema), [formSchema]);

  // Create per-step schemas
  const stepSchemas = useMemo(() => {
    if (!hasMultipleSteps || !objectSchema) return [];
    return steps.map((_, index) =>
      createStepSchema(objectSchema, index, fieldAssignments)
    );
  }, [hasMultipleSteps, objectSchema, steps, fieldAssignments]);

  // Current step info
  const currentStep = steps[currentStepIndex];
  const currentStepSchema = stepSchemas[currentStepIndex];
  const isFirst = currentStepIndex === 0;
  const isLast = currentStepIndex === steps.length - 1;

  // Build field config for current step
  const currentStepFieldConfig = useMemo(() => {
    if (!fieldConfig) return undefined;
    // Filter field config to only include fields for current step
    const stepFields = Array.from(fieldAssignments.entries())
      .filter(([, step]) => step === currentStepIndex)
      .map(([field]) => field);

    const filtered: Record<string, unknown> = {};
    for (const field of stepFields) {
      if (field in (fieldConfig as Record<string, unknown>)) {
        filtered[field] = (fieldConfig as Record<string, unknown>)[field];
      }
    }
    return filtered as FieldConfig<z.infer<SchemaType>>;
  }, [fieldConfig, fieldAssignments, currentStepIndex]);

  // Get values for current step
  const currentStepValues = useMemo(() => {
    const stepFields = Array.from(fieldAssignments.entries())
      .filter(([, step]) => step === currentStepIndex)
      .map(([field]) => field);

    const values: Record<string, unknown> = {};
    for (const field of stepFields) {
      if (field in accumulatedValues) {
        values[field] = accumulatedValues[field];
      }
    }
    return values;
  }, [fieldAssignments, currentStepIndex, accumulatedValues]);

  // Handle step navigation - only allow navigation to completed steps or the current step
  const handleStepClick = useCallback(
    (stepId: string) => {
      const stepIndex = steps.findIndex((s) => s.id === stepId);
      if (stepIndex === -1) return;

      // Allow navigation only to:
      // - The current step
      // - Previously completed steps
      // - The next step after current (if current step is completed)
      const canNavigate =
        stepIndex === currentStepIndex ||
        completedSteps.has(stepIndex) ||
        (stepIndex === currentStepIndex + 1 && completedSteps.has(currentStepIndex));

      if (canNavigate) {
        setCurrentStepIndex(stepIndex);
        // Clear schema errors when navigating to allow user to retry
        setSchemaErrors(null);
      }
    },
    [steps, currentStepIndex, completedSteps]
  );

  // Handle step value changes - accumulate and notify parent
  // Uses refs to avoid stale closures, ensuring values from other steps are preserved
  const handleStepValuesChange = useCallback(
    (stepValues: Record<string, unknown>, form?: UseFormReturn<Record<string, unknown>>) => {
      // stepValues contains only the current step's fields, merge with latest accumulated values
      const newAccumulated = { ...accumulatedValuesRef.current, ...stepValues };
      accumulatedValuesRef.current = newAccumulated;
      setAccumulatedValues(newAccumulated);
      // Notify parent of accumulated values (form is undefined for multi-step as we don't have a single form instance)
      onValuesChangeRef.current?.(newAccumulated as Partial<z.infer<SchemaType>>, form as UseFormReturn<z.infer<SchemaType>> | undefined);
    },
    []
  );

  // Handle step submission - AutoForm validates per-step, we just accumulate and track completion
  // Uses refs to avoid stale closures, ensuring values from other steps are preserved
  const handleStepSubmit = useCallback(
    (stepValues: Record<string, unknown>) => {
      // AutoForm has already validated the current step's fields via zodResolver
      const newAccumulated = { ...accumulatedValuesRef.current, ...stepValues };
      accumulatedValuesRef.current = newAccumulated;
      setAccumulatedValues(newAccumulated);

      // Notify parent of accumulated values (form is undefined for multi-step as we don't have a single form instance)
      onValuesChangeRef.current?.(newAccumulated as Partial<z.infer<SchemaType>>, undefined);

      // Mark current step as completed (validation passed via AutoForm)
      setCompletedSteps((prev) => new Set([...prev, currentStepIndex]));

      if (isLast) {
        // Final submit - check all steps completed and validate full schema
        const allStepsCompleted = steps.every(
          (_, index) => index === currentStepIndex || completedSteps.has(index)
        );

        if (!allStepsCompleted) {
          // Navigate to first incomplete step
          const firstIncompleteStep = steps.findIndex(
            (_, index) => index !== currentStepIndex && !completedSteps.has(index)
          );
          if (firstIncompleteStep !== -1) {
            setCurrentStepIndex(firstIncompleteStep);
            return;
          }
        }

        // Validate against full schema (handles cross-field validations)
        const parseResult = formSchema.safeParse(newAccumulated);
        if (parseResult.success) {
          setSchemaErrors(null);
          onSubmit?.(parseResult.data as z.infer<SchemaType>);
        } else {
          // Store errors to display to the user
          setSchemaErrors(parseResult.error);

          // Try to navigate to the step containing the first error
          const firstErrorPath = parseResult.error.issues[0]?.path[0];
          if (typeof firstErrorPath === "string") {
            const errorFieldStep = fieldAssignments.get(firstErrorPath);
            if (errorFieldStep !== undefined && errorFieldStep !== currentStepIndex) {
              setCurrentStepIndex(errorFieldStep);
            }
          }
        }
      } else {
        // Move to next step
        setCurrentStepIndex((prev) => prev + 1);
        }
      },
    [isLast, onSubmit, currentStepIndex, steps, completedSteps, formSchema, fieldAssignments]
  );

  // Handle back button
  const handleBack = useCallback(() => {
    if (!isFirst) {
      setCurrentStepIndex((prev) => prev - 1);
      // Clear schema errors when navigating to allow user to retry
      setSchemaErrors(null);
    }
  }, [isFirst]);

  // If no multiple steps, delegate to regular AutoForm
  if (!hasMultipleSteps) {
    return (
      <AutoForm
        formSchema={formSchema}
        values={initialValues}
        onValuesChange={onValuesChange}
        onSubmit={onSubmit}
        fieldConfig={fieldConfig}
        className={className}
      >
        <Button type="submit" disabled={isSubmitting} className="w-full mt-4">
          {submitButtonText}
        </Button>
        {children}
      </AutoForm>
    );
  }

  // Multi-step form rendering
  if (!currentStepSchema || !currentStep) {
    return null;
  }

  return (
    <div className={cn("w-full", className)}>
      {/* Stepper Header */}
      <StepperComponent
        steps={steps.map((s) => ({ id: s.id, label: s.title }))}
        currentStepIndex={currentStepIndex}
        currentStepId={currentStep.id}
        onStepClick={handleStepClick}
        isFirst={isFirst}
        isLast={isLast}
      />

      {/* Step Title */}
      <div className="mb-4">
        <h3 className="text-lg font-semibold">{currentStep.title}</h3>
        <p className="text-sm text-muted-foreground">
          Step {currentStepIndex + 1} of {steps.length}
        </p>
      </div>

      {/* Schema Validation Errors */}
      {schemaErrors && schemaErrors.issues.length > 0 && (
        <div
          role="alert"
          aria-live="assertive"
          className="rounded-md border border-destructive/50 bg-destructive/10 p-4 mb-4"
        >
          <div className="flex items-start gap-3">
            <svg
              className="h-5 w-5 text-destructive shrink-0 mt-0.5"
              fill="none"
              viewBox="0 0 24 24"
              stroke="currentColor"
              strokeWidth={2}
            >
              <path
                strokeLinecap="round"
                strokeLinejoin="round"
                d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z"
              />
            </svg>
            <div className="flex-1">
              <h4 className="text-sm font-medium text-destructive">
                Validation Failed
              </h4>
              <ul className="mt-2 text-sm text-destructive/90 list-disc list-inside space-y-1">
                {schemaErrors.issues.map((issue, index) => (
                  <li key={index}>
                    {issue.path.length > 0 && (
                      <span className="font-medium">{issue.path.join(".")}: </span>
                    )}
                    {issue.message}
                  </li>
                ))}
              </ul>
            </div>
            <button
              type="button"
              onClick={() => setSchemaErrors(null)}
              className="text-destructive/70 hover:text-destructive shrink-0"
              aria-label="Dismiss errors"
            >
              <svg className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}>
                <path strokeLinecap="round" strokeLinejoin="round" d="M6 18L18 6M6 6l12 12" />
              </svg>
            </button>
          </div>
        </div>
      )}

      {/* Current Step Form */}
      <AutoForm
        key={currentStep.id}
        formSchema={currentStepSchema as z.ZodObject<z.ZodRawShape>}
        values={currentStepValues}
        onValuesChange={handleStepValuesChange}
        onSubmit={handleStepSubmit}
        fieldConfig={currentStepFieldConfig}
        className="space-y-4"
      >
        {/* Navigation Buttons */}
        <div className="flex justify-between pt-4">
          <Button
            type="button"
            variant="outline"
            onClick={handleBack}
            disabled={isFirst || isSubmitting}
          >
            {backButtonText}
          </Button>
          <Button type="submit" disabled={isSubmitting}>
            {isLast ? submitButtonText : nextButtonText}
          </Button>
        </div>
        {children}
      </AutoForm>
    </div>
  );
}

import React from "react";
import type { DefaultValues } from "react-hook-form";
import { z } from "zod";
import type { AutoFormInputComponentProps, FieldConfig } from "./types";

export const BUILTIN_FIELD_TYPES = [
	"checkbox",
	"date",
	"select",
	"radio",
	"switch",
	"textarea",
	"number",
	"fallback",
] as const;

/**
 * Get the type name from a Zod v4 schema's _zod.def.
 * In Zod v4: _zod.def.type (e.g., "default", "optional", "object", "string")
 */
function getDefTypeName(schema: z.ZodType): string {
  // Access through _zod.def.type for Zod v4
  const def = (schema as any)._zod?.def;
  return def?.type || "";
}

/**
 * Type for wrapped object schemas in Zod v4.
 * In Zod v4, ZodEffects is replaced with ZodPipe for transforms.
 * For autoform purposes, we mainly deal with objects that might be wrapped in optional/default/nullable.
 */
export type ZodObjectOrWrapped = z.ZodObject<any, any> | z.ZodType<any>;

/**
 * Beautify a camelCase string.
 * e.g. "myString" -> "My String"
 */
export function beautifyObjectName(string: string) {
  // if numbers only return the string
  let output = string.replace(/([A-Z])/g, " $1");
  output = output.charAt(0).toUpperCase() + output.slice(1);
  return output;
}

/**
 * Get the lowest level Zod type.
 * This will unpack optionals, defaults, nullables, pipes, etc.
 */
export function getBaseSchema<ChildType extends z.ZodType = z.ZodType>(
  schema: ChildType
): ChildType | null {
  if (!schema) return null;

  const def = (schema as any)._zod?.def;
  if (!def) return schema as ChildType;

  // Handle wrapped types by checking for innerType or wrapped property
  if (def.innerType) {
    return getBaseSchema(def.innerType as ChildType);
  }

  // Handle ZodPipe (transforms) - get the output schema
  if (def.out) {
    return getBaseSchema(def.out as ChildType);
  }

  // Handle schema property (for some wrapper types)
  if (def.schema) {
    return getBaseSchema(def.schema as ChildType);
  }

  return schema as ChildType;
}

/**
 * Get the type name of the lowest level Zod type.
 * This will unpack optionals, defaults, etc.
 * 
 * Returns Zod v4 style type names (e.g., "enum", "boolean", "object")
 */
export function getBaseType(schema: z.ZodType): string {
  const baseSchema = getBaseSchema(schema);
  if (!baseSchema) return "";

  const typeName = getDefTypeName(baseSchema);

  // Map to consistent type names (capitalize first letter for component lookup)
  const typeMap: Record<string, string> = {
    object: "ZodObject",
    array: "ZodArray",
    string: "ZodString",
    number: "ZodNumber",
    int: "ZodNumber",
    float: "ZodNumber",
    boolean: "ZodBoolean",
    date: "ZodDate",
    enum: "ZodEnum",
    nativeEnum: "ZodNativeEnum",
    literal: "ZodLiteral",
    union: "ZodUnion",
  };

  return typeMap[typeName] || typeName;
}

/**
 * Search for a "default" wrapper in the Zod stack and return its value.
 * In Zod v4: _zod.def.defaultValue is the default value (not a function)
 */
export function getDefaultValueInZodStack(schema: z.ZodType): any {
  const def = (schema as any)._zod?.def;
  if (!def) return undefined;

  if (def.type === "default") {
    // In Zod v4, defaultValue is the value directly (not a function)
    const defaultValue = def.defaultValue;
    // Handle both function (legacy) and value
    if (typeof defaultValue === "function") {
      return defaultValue();
    }
    return defaultValue;
  }

  // Check wrapped types
  if (def.innerType) {
    return getDefaultValueInZodStack(def.innerType);
  }
  if (def.schema) {
    return getDefaultValueInZodStack(def.schema);
  }

  return undefined;
}

/**
 * Get all default values from a Zod schema.
 */
export function getDefaultValues<Schema extends z.ZodObject<any, any>>(
  schema: Schema,
  fieldConfig?: FieldConfig<z.infer<Schema>>
) {
  if (!schema) return null;
  const { shape } = schema;
  type DefaultValuesType = DefaultValues<Partial<z.infer<Schema>>>;
  const defaultValues = {} as DefaultValuesType;
  if (!shape) return defaultValues;

  for (const key of Object.keys(shape)) {
    const item = shape[key] as z.ZodType;

    if (getBaseType(item) === "ZodObject") {
      const defaultItems = getDefaultValues(
        getBaseSchema(item) as unknown as z.ZodObject<any, any>,
        fieldConfig?.[key] as FieldConfig<z.infer<Schema>>
      );

      if (defaultItems !== null) {
        for (const defaultItemKey of Object.keys(defaultItems)) {
          const pathKey = `${key}.${defaultItemKey}` as keyof DefaultValuesType;
          (defaultValues as any)[pathKey] = defaultItems[defaultItemKey];
        }
      }
    } else {
      let defaultValue = getDefaultValueInZodStack(item);
      // Also check fieldConfig for default values (important for JSON schema derived forms)
      if (
        (defaultValue === undefined || defaultValue === null || defaultValue === "") &&
        fieldConfig?.[key]?.inputProps
      ) {
        defaultValue = (fieldConfig?.[key]?.inputProps as unknown as any)
          .defaultValue;
      }
      if (defaultValue !== undefined) {
        (defaultValues as any)[key as keyof DefaultValuesType] = defaultValue;
      }
    }
  }

  return defaultValues;
}

/**
 * Extract the object schema from a potentially wrapped schema.
 * Handles pipes, defaults, optionals, etc.
 */
export function getObjectFormSchema(
  schema: ZodObjectOrWrapped
): z.ZodObject<any, any> {
  if (!schema) return schema as z.ZodObject<any, any>;

  const def = (schema as any)._zod?.def;
  if (!def) return schema as z.ZodObject<any, any>;

  // If it's a pipe (transform), get the input schema
  if (def.type === "pipe") {
    return getObjectFormSchema(def.in);
  }

  // Handle wrapped types
  if (def.innerType) {
    return getObjectFormSchema(def.innerType);
  }
  if (def.schema) {
    return getObjectFormSchema(def.schema);
  }

  return schema as z.ZodObject<any, any>;
}

/**
 * Get description from a Zod schema.
 * In Zod v4, descriptions are stored in the global registry.
 */
export function getSchemaDescription(schema: z.ZodType): string | undefined {
  // Try to get from registry first (Zod v4)
  const registered = z.globalRegistry.get(schema);
  if (registered?.description) {
    return registered.description;
  }

  // Fallback: check if description is on the schema itself
  const def = (schema as any)._zod?.def;
  return def?.description;
}

/**
 * Convert a Zod schema to HTML input props to give direct feedback to the user.
 * Once submitted, the schema will be validated completely.
 */
export function zodToHtmlInputProps(
  schema: z.ZodType
): React.InputHTMLAttributes<HTMLInputElement> {
  const def = (schema as any)._zod?.def;
  const defType = def?.type || "";

  // Check for optional/nullable
  if (["optional", "nullable"].includes(defType)) {
    return {
      ...zodToHtmlInputProps(def.innerType),
      required: false,
    };
  }

  // Check for default - fields with defaults should not be required
  // since the default value will be used if not provided
  if (defType === "default") {
    return {
      ...zodToHtmlInputProps(def.innerType),
      required: false,
    };
  }

  const inputProps: React.InputHTMLAttributes<HTMLInputElement> = {
    required: true,
  };

  // Get checks from the schema
  const checks = def?.checks;
  if (!checks || !Array.isArray(checks)) {
    return inputProps;
  }

  const type = getBaseType(schema);

  for (const check of checks) {
    // In Zod v4, checks have 'kind' property
    const checkKind = check.kind || check.type;

    if (checkKind === "min" || checkKind === "min_length") {
      if (type === "ZodString") {
        inputProps.minLength = check.value ?? check.minimum;
      } else {
        inputProps.min = check.value ?? check.minimum;
      }
    }
    if (checkKind === "max" || checkKind === "max_length") {
      if (type === "ZodString") {
        inputProps.maxLength = check.value ?? check.maximum;
      } else {
        inputProps.max = check.value ?? check.maximum;
      }
    }
  }

  return inputProps;
}

/**
 * Sort the fields by order.
 * If no order is set, the field will be sorted based on the order in the schema.
 */
export function sortFieldsByOrder<SchemaType extends z.ZodObject<any, any>>(
  fieldConfig: FieldConfig<z.infer<SchemaType>> | undefined,
  keys: string[]
) {
  const sortedFields = keys.sort((a, b) => {
    const fieldA: number = (fieldConfig?.[a]?.order as number) ?? 0;
    const fieldB = (fieldConfig?.[b]?.order as number) ?? 0;
    return fieldA - fieldB;
  });

  return sortedFields;
}

// Import shared JSON Schema property type for consistency with form-builder
import type { JSONSchemaPropertyBase } from "./shared-form-types";

/**
 * JSON schema property shape that includes FieldConfigItem-compatible metadata.
 * Uses the shared type for consistency between form-builder and auto-form.
 */
type JsonSchemaProperty = JSONSchemaPropertyBase;

export function buildFieldConfigFromJsonSchema(
	jsonSchema: Record<string, unknown>,
	fieldComponents?: Record<
		string,
		React.ComponentType<AutoFormInputComponentProps>
	>,
): FieldConfig<Record<string, unknown>> {
	const fieldConfig: FieldConfig<Record<string, unknown>> = {};
	const properties = jsonSchema.properties as Record<string, JsonSchemaProperty>;

	if (!properties) return fieldConfig;

	for (const [key, value] of Object.entries(properties)) {
		const config: Record<string, unknown> = {};

		// Extract label from meta (support both 'label' and JSON Schema 'title')
		if (value.label) {
			config.label = value.label;
		} else if (value.title) {
			config.label = value.title;
		}

		// Extract description from meta
		if (value.description) {
			config.description = value.description;
		}

		// Extract inputProps from meta (includes placeholder, type, etc.)
		// Also merge in default value if present
		const inputProps: Record<string, unknown> = value.inputProps ? { ...value.inputProps } : {};

		// Extract placeholder from JSON Schema
		if (value.placeholder) {
			inputProps.placeholder = value.placeholder;
		}

		// Extract default value from JSON schema and pass it via inputProps
		// Also mark field as not required if it has a default value
		if (value.default !== undefined) {
			inputProps.defaultValue = value.default;
			inputProps.required = false;
		}

		if (Object.keys(inputProps).length > 0) {
			config.inputProps = inputProps;
		}

		// Extract order from meta
		if (value.order !== undefined) {
			config.order = value.order;
		}

		// Extract fieldType from JSON Schema meta
		// Also detect date-time format from JSON Schema (from z.date() -> toJSONSchema with override)
		let fieldType = value.fieldType;

		// Auto-detect date fields from JSON Schema format: "date-time"
		// This handles the roundtrip: z.date() -> toJSONSchema (with override) -> { type: "string", format: "date-time" }
		if (!fieldType && value.type === "string" && value.format === "date-time") {
			fieldType = "date";
		}

		if (fieldType) {
			// 1. Check if there's a custom component in fieldComponents
			const CustomComponent = fieldComponents?.[fieldType];
			if (CustomComponent) {
				config.fieldType = (props: AutoFormInputComponentProps) => (
					<CustomComponent {...props} />
				);
			}
			// 2. For built-in types, pass through to auto-form
			else if (
				BUILTIN_FIELD_TYPES.includes(
					fieldType as (typeof BUILTIN_FIELD_TYPES)[number],
				)
			) {
				config.fieldType = fieldType;
			}
			// 3. Unknown custom type without a component - log warning and skip
			else {
				console.warn(
					`CMS: Unknown fieldType "${fieldType}" for field "${key}". ` +
						`Provide a component via fieldComponents override or use a built-in type.`,
				);
			}
		}

		// Reserved FieldConfigItem property names that should not be overwritten by nested field configs.
		// If a nested field has the same name as a reserved property (e.g., a field named "description"),
		// we skip it to prevent overwriting the parent's config (like its help text).
		const reservedProps = new Set([
			"description",
			"label",
			"inputProps",
			"fieldType",
			"renderParent",
			"order",
		]);

		// Handle nested object properties recursively
		if (value.properties) {
			const nestedConfig = buildFieldConfigFromJsonSchema(
				{ properties: value.properties } as Record<string, unknown>,
				fieldComponents,
			);

			// Merge nested config, but skip keys that match reserved property names
			for (const [nestedKey, nestedValue] of Object.entries(nestedConfig)) {
				if (!reservedProps.has(nestedKey)) {
					config[nestedKey] = nestedValue;
				} else {
					console.warn(
						`Field "${key}" has a nested field named "${nestedKey}" which conflicts with a reserved FieldConfigItem property. ` +
							`The nested field's config will not be accessible at the parent level.`,
					);
				}
			}
		}

		// Handle array items recursively — for `z.array(z.object({...}))` shapes
		// the array's items.properties carry per-item field metadata (placeholder,
		// fieldType, relation config, etc.) that AutoFormArray needs to forward
		// to its inner AutoFormObject. Mirror the nested-object merge so per-item
		// configs end up at `fieldConfig[arrayKey][itemPropertyKey]`.
		const items = value.items as JsonSchemaProperty | undefined;
		if (items?.properties) {
			const itemConfig = buildFieldConfigFromJsonSchema(
				{ properties: items.properties } as Record<string, unknown>,
				fieldComponents,
			);

			for (const [itemKey, itemValue] of Object.entries(itemConfig)) {
				if (!reservedProps.has(itemKey)) {
					config[itemKey] = itemValue;
				} else {
					console.warn(
						`Array field "${key}" has an item property named "${itemKey}" which conflicts with a reserved FieldConfigItem property. ` +
							`The item field's config will not be accessible inside array items.`,
					);
				}
			}
		}

		if (Object.keys(config).length > 0) {
			fieldConfig[key] = config;
		}
	}

	return fieldConfig;
}

import type { ControllerRenderProps, FieldValues } from "react-hook-form";
import * as z from "zod";
import { INPUT_COMPONENTS } from "./config";
import type { 
  SerializableInputProps,
  StringInputProps,
  NumberInputProps,
  BooleanInputProps,
  DateInputProps,
  EnumInputProps,
  TypedInputProps,
} from "./shared-form-types";

// Re-export discriminated input prop types for field components
export type {
  SerializableInputProps,
  StringInputProps,
  NumberInputProps,
  BooleanInputProps,
  DateInputProps,
  EnumInputProps,
  TypedInputProps,
};

/**
 * Available field types for AutoForm fieldConfig.
 * These map to the input components in ./config.ts
 */
export type AutoFormFieldType = keyof typeof INPUT_COMPONENTS;

/**
 * Input props for form fields.
 * 
 * This is the runtime type that accepts any input props.
 * For type-safe props, use the discriminated types:
 * - StringInputProps for text inputs
 * - NumberInputProps for number inputs
 * - BooleanInputProps for checkboxes/switches
 * - DateInputProps for date pickers
 * - EnumInputProps for selects/radios
 */
export type FieldInputProps = SerializableInputProps & 
  Omit<React.InputHTMLAttributes<HTMLInputElement>, keyof SerializableInputProps> &
  Omit<React.TextareaHTMLAttributes<HTMLTextAreaElement>, keyof SerializableInputProps>;

/**
 * Configuration for a single field in AutoForm.
 * 
 * Note: This type is designed to align with form-builder's FormBuilderFieldProps
 * so that JSON Schema properties can be easily converted to field configs.
 */
export type FieldConfigItem = {
  /** Description text or React node */
  description?: React.ReactNode;
  /** Input props passed to the field component */
  inputProps?: FieldInputProps;
  /** Display label */
  label?: string;
  /** Field type override - built-in type or custom component */
  fieldType?:
    | keyof typeof INPUT_COMPONENTS
    | React.FC<AutoFormInputComponentProps>;
  /** Wrapper component for custom field layout */
  renderParent?: (props: {
    children: React.ReactNode;
  }) => React.ReactElement | null;
  /** Display order for field ordering */
  order?: number;
};

/**
 * FieldConfig for nested objects - allows both FieldConfigItem properties
 * AND nested field configs for child properties.
 */
export type FieldConfigObject = FieldConfigItem & {
  [key: string]: FieldConfigItem | FieldConfigObject | undefined;
};

/**
 * For object fields, allow both FieldConfigItem properties (label, description, etc.)
 * AND nested field configs for the object's properties.
 */
// eslint-disable-next-line @typescript-eslint/no-explicit-any -- Required for Zod generic inference
export type FieldConfig<SchemaType extends z.infer<z.ZodObject<any, any>>> = {
  [Key in keyof SchemaType]?: FieldConfigItem | FieldConfigObject;
};

export enum DependencyType {
  DISABLES,
  REQUIRES,
  HIDES,
  SETS_OPTIONS,
}

// eslint-disable-next-line @typescript-eslint/no-explicit-any -- Required for Zod generic inference
type BaseDependency<SchemaType extends z.infer<z.ZodObject<any, any>>> = {
  sourceField: keyof SchemaType;
  type: DependencyType;
  targetField: keyof SchemaType;
  // eslint-disable-next-line @typescript-eslint/no-explicit-any -- Dynamic field value types
  when: (sourceFieldValue: any, targetFieldValue: any) => boolean;
};

// eslint-disable-next-line @typescript-eslint/no-explicit-any -- Required for Zod generic inference
export type ValueDependency<SchemaType extends z.infer<z.ZodObject<any, any>>> =
  BaseDependency<SchemaType> & {
    type:
      | DependencyType.DISABLES
      | DependencyType.REQUIRES
      | DependencyType.HIDES;
  };

export type EnumValues = readonly [string, ...string[]];

export type OptionsDependency<
  // eslint-disable-next-line @typescript-eslint/no-explicit-any -- Required for Zod generic inference
  SchemaType extends z.infer<z.ZodObject<any, any>>,
> = BaseDependency<SchemaType> & {
  type: DependencyType.SETS_OPTIONS;

  // Partial array of values from sourceField that will trigger the dependency
  options: EnumValues;
};

// eslint-disable-next-line @typescript-eslint/no-explicit-any -- Required for Zod generic inference
export type Dependency<SchemaType extends z.infer<z.ZodObject<any, any>>> =
  | ValueDependency<SchemaType>
  | OptionsDependency<SchemaType>;

/**
 * A FormInput component can handle a specific Zod type (e.g. "ZodBoolean")
 */
export type AutoFormInputComponentProps = {
  zodInputProps: React.InputHTMLAttributes<HTMLInputElement>;
  // eslint-disable-next-line @typescript-eslint/no-explicit-any -- react-hook-form field name type
  field: ControllerRenderProps<FieldValues, any>;
  fieldConfigItem: FieldConfigItem;
  label: string;
  isRequired: boolean;
  // eslint-disable-next-line @typescript-eslint/no-explicit-any -- Dynamic field props from Zod schema
  fieldProps: any;
  zodItem: z.ZodType;
  className?: string;
};

import type { z } from "zod";
import type { 
  JSONSchemaPropertyBase, 
  SerializableInputProps,
  FieldType,
  StringInputProps,
  NumberInputProps,
  BooleanInputProps,
  DateInputProps,
  EnumInputProps,
  InputPropsByBackingType,
} from "../auto-form/shared-form-types";

// Re-export discriminated input prop types from shared-form-types
export type {
  SerializableInputProps,
  StringInputProps,
  NumberInputProps,
  BooleanInputProps,
  DateInputProps,
  EnumInputProps,
  InputPropsByBackingType,
};

// ============================================================================
// STEP TYPES
// ============================================================================

/**
 * Represents a step in a multi-step form.
 */
export interface FormStep {
  /** Unique identifier for the step */
  id: string;
  /** Display title for the step */
  title: string;
}

/**
 * JSON Schema types for form builder I/O.
 * Extends the shared base types with form-builder specific needs.
 */
export interface JSONSchema {
  type: "object";
  properties: Record<string, JSONSchemaProperty>;
  required?: string[];
  $schema?: string;
  /** Step definitions for multi-step forms (stored in schema meta) */
  steps?: FormStep[];
  additionalProperties?: boolean;
}

/**
 * JSON Schema property with form-builder metadata.
 * Extends the shared JSONSchemaPropertyBase for compatibility with auto-form.
 */
export interface JSONSchemaProperty extends Omit<JSONSchemaPropertyBase, "type" | "enum" | "properties" | "items"> {
  /** JSON Schema type - required for form-builder fields */
  type: string;
  /** Enum values for select/radio fields (string-only for form-builder) */
  enum?: string[];
  /** Nested properties for object types (self-referential) */
  properties?: Record<string, JSONSchemaProperty>;
  /** Item schema for array types (self-referential) */
  items?: JSONSchemaProperty;
  /** Minimum items for array types */
  minItems?: number;
  /** Maximum items for array types */
  maxItems?: number;
  /** Step group index for multi-step forms (0-indexed) */
  stepGroup?: number;
}

/**
 * Internal field representation used by form builder.
 */
export interface FormBuilderField {
  id: string;
  type: string;
  props: FormBuilderFieldProps;
  /** Nested fields for object type containers */
  children?: FormBuilderField[];
  /** Template fields defining the shape of each array item */
  itemTemplate?: FormBuilderField[];
  /** Step group index (0-indexed) for multi-step forms */
  stepGroup?: number;
}

/**
 * Backing types supported by form-builder fields.
 */
export type BackingType = keyof InputPropsByBackingType;

// ============================================================================
// COMPONENT TYPE REGISTRY
// ============================================================================

/**
 * Registry mapping component type names to their backing Zod types.
 * This enables compile-time type checking for component definitions.
 */
export const COMPONENT_BACKING_TYPES = {
  text: "string",
  email: "string",
  password: "string",
  url: "string",
  phone: "string",
  textarea: "string",
  number: "number",
  checkbox: "boolean",
  switch: "boolean",
  select: "enum",
  radio: "enum",
  date: "date",
  color: "string", // color picker stores hex string
} as const;

/**
 * All registered component type names.
 */
export type ComponentType = keyof typeof COMPONENT_BACKING_TYPES;

/**
 * Get the backing type for a component type.
 */
export type BackingTypeFor<C extends ComponentType> = typeof COMPONENT_BACKING_TYPES[C];

// ============================================================================
// DISCRIMINATED FIELD PROPS BY BACKING TYPE
// ============================================================================

/**
 * Base properties shared by all form builder fields.
 */
export interface BaseFieldProps {
  /** Display label for the field */
  label: string;
  /** Description text */
  description?: string;
  /** Whether the field is required */
  required?: boolean;
  /** Field type override (checkbox, date, select, radio, switch, etc.) */
  fieldType?: FieldType;
  /** Additional input props passed through to the field */
  inputProps?: SerializableInputProps;
}

/**
 * Props for string-backed fields (text, email, password, url, phone, textarea).
 */
export interface StringFieldProps extends BaseFieldProps {
  /** Placeholder text */
  placeholder?: string;
  /** Minimum length */
  minLength?: number;
  /** Maximum length */
  maxLength?: number;
  /** Regex pattern for validation */
  pattern?: string;
  /** HTML input type (text, email, password, tel, url) */
  inputType?: string;
  /** Default value */
  defaultValue?: string;
}

/**
 * Props for number-backed fields.
 */
export interface NumberFieldProps extends BaseFieldProps {
  /** Placeholder text */
  placeholder?: string;
  /** Minimum value */
  min?: number;
  /** Maximum value */
  max?: number;
  /** Default value */
  defaultValue?: number;
}

/**
 * Props for boolean-backed fields (checkbox, switch).
 */
export interface BooleanFieldProps extends BaseFieldProps {
  /** Default value */
  defaultValue?: boolean;
}

/**
 * Props for date-backed fields.
 */
export interface DateFieldProps extends BaseFieldProps {
  /** Minimum date */
  minDate?: Date | string;
  /** Maximum date */
  maxDate?: Date | string;
  /** Default value */
  defaultValue?: Date | string;
}

/**
 * Props for enum-backed fields (select, radio).
 */
export interface EnumFieldProps extends BaseFieldProps {
  /** Placeholder text (for select) */
  placeholder?: string;
  /** Options for the select/radio */
  options?: string[];
  /** Default value (must match one of the options) */
  defaultValue?: string;
}

/**
 * Maps backing types to their corresponding field props.
 */
export interface FieldPropsByBackingType {
  string: StringFieldProps;
  number: NumberFieldProps;
  boolean: BooleanFieldProps;
  date: DateFieldProps;
  enum: EnumFieldProps;
}

/**
 * Get the correct field props type for a backing type.
 */
export type FieldPropsFor<T extends BackingType> = FieldPropsByBackingType[T];

/**
 * Union of all discriminated field props.
 */
export type TypedFieldProps = 
  | StringFieldProps
  | NumberFieldProps
  | BooleanFieldProps
  | DateFieldProps
  | EnumFieldProps;

/**
 * Properties for a form builder field.
 * This is the runtime union type used when the backing type is not known.
 * 
 * For type-safe field props, use the discriminated variants:
 * - StringFieldProps for text, email, password, url, phone, textarea
 * - NumberFieldProps for number fields
 * - BooleanFieldProps for checkbox, switch
 * - DateFieldProps for date fields
 * - EnumFieldProps for select, radio
 */
export interface FormBuilderFieldProps extends BaseFieldProps {
  // String field props
  placeholder?: string;
  minLength?: number;
  maxLength?: number;
  pattern?: string;
  inputType?: string;

  // Number field props
  min?: number;
  max?: number;

  // Date field props
  minDate?: Date | string;
  maxDate?: Date | string;

  // Enum field props
  options?: string[];

  // Array field props
  minItems?: number;
  maxItems?: number;

  // Default value (type depends on backing type)
  defaultValue?: unknown;
}

/**
 * Typed component definition for a specific backing type.
 * 
 * Use this when defining components to get type-safe field props:
 * 
 * @example
 * ```typescript
 * const textField: TypedComponentDefinition<"string"> = {
 *   type: "text",
 *   backingType: "string",
 *   defaultProps: { label: "Text", placeholder: "Enter text" }, // ✓ type-safe
 *   // ...
 * };
 * ```
 */
export interface TypedComponentDefinition<T extends BackingType> {
  /** Unique identifier for this component type */
  type: ComponentType | string;
  /** The backing Zod type for this component */
  backingType: T;
  /** Display name shown in the palette */
  label: string;
  /** Icon shown in the palette */
  icon?: React.ComponentType<{ className?: string }>;
  /** Default props when a new field is created - type-safe based on backing type */
  defaultProps: Partial<FieldPropsFor<T>>;
  /** Zod schema for the property panel */
  propertiesSchema: z.ZodObject<z.ZodRawShape>;
  /** Convert field props to JSON Schema property */
  toJSONSchema: (props: FieldPropsFor<T>, isRequired: boolean) => JSONSchemaProperty;
  /** Try to parse a JSON Schema property into this component type */
  fromJSONSchema: (prop: JSONSchemaProperty, key: string, isRequired: boolean) => 
    { id: string; type: string; props: FieldPropsFor<T> } | null;
  /** Optional custom preview component */
  PreviewComponent?: React.ComponentType<{ field: FormBuilderField }>;
}

/**
 * Component definition provided by developers.
 * 
 * This is the runtime type used when the backing type is not known at compile time.
 * For type-safe definitions, use `TypedComponentDefinition<T>`.
 */
export interface FormBuilderComponentDefinition {
  /** Unique identifier for this component type */
  type: string;
  /** The backing Zod type for this component (optional for backwards compatibility) */
  backingType?: BackingType;
  /** Display name shown in the palette */
  label: string;
  /** Icon shown in the palette */
  icon?: React.ComponentType<{ className?: string }>;
  /** Default props when a new field is created */
  defaultProps: Partial<FormBuilderFieldProps>;
  /** Zod schema for the property panel */
  propertiesSchema: z.ZodObject<z.ZodRawShape>;
  /** Convert field props to JSON Schema property */
  toJSONSchema: (props: FormBuilderFieldProps, isRequired: boolean) => JSONSchemaProperty;
  /** Try to parse a JSON Schema property into this component type */
  fromJSONSchema: (prop: JSONSchemaProperty, key: string, isRequired: boolean) => FormBuilderField | null;
  /** Optional custom preview component */
  PreviewComponent?: React.ComponentType<{ field: FormBuilderField }>;
}

/**
 * Helper to create a type-safe component definition.
 * The returned definition is assignable to FormBuilderComponentDefinition.
 */
export function defineComponent<T extends BackingType>(
  def: TypedComponentDefinition<T>
): FormBuilderComponentDefinition {
  return def as unknown as FormBuilderComponentDefinition;
}

/**
 * Form builder context for sharing state
 */
export interface FormBuilderContextValue {
  fields: FormBuilderField[];
  components: FormBuilderComponentDefinition[];
  mode: "build" | "preview";
  setFields: (fields: FormBuilderField[]) => void;
  setMode: (mode: "build" | "preview") => void;
  addField: (componentType: string, index?: number) => void;
  updateField: (id: string, props: Partial<FormBuilderFieldProps>) => void;
  removeField: (id: string) => void;
  moveField: (fromIndex: number, toIndex: number) => void;
}

/**
 * Drag data types for dnd-kit
 */
export interface PaletteDragData {
  type: "palette";
  componentType: string;
}

export interface FieldDragData {
  type: "field";
  fieldId: string;
  index: number;
}

export type DragData = PaletteDragData | FieldDragData;

"use client";

import { PageLayout } from "./page-layout";
import { StackAttribution } from "./stack-attribution";

export interface PageWrapperProps {
	children: React.ReactNode;
	className?: string;
	testId?: string;
	/**
	 * Whether to show the "Powered by BTST" attribution.
	 * Defaults to true.
	 */
	showAttribution?: boolean;
}

/**
 * Shared page wrapper component providing consistent layout and optional attribution
 * for plugin pages. Used by blog, CMS, and other plugins.
 *
 * @example
 * ```tsx
 * <PageWrapper testId="my-page" showAttribution={false}>
 *   <div className="w-full max-w-5xl">
 *     <h1>My Page</h1>
 *   </div>
 * </PageWrapper>
 * ```
 */
export function PageWrapper({
	children,
	className,
	testId,
	showAttribution = true,
}: PageWrapperProps) {
	return (
		<>
			<PageLayout className={className} data-testid={testId}>
				{children}
			</PageLayout>

			{showAttribution && <StackAttribution />}
		</>
	);
}

import { z } from "zod";

// ============================================================================
// TYPES
// ============================================================================

export interface FormStep {
  id: string;
  title: string;
}

export interface FormSchemaMetadata {
  /** Multi-step form step definitions */
  steps?: FormStep[];
  /** Map of field names to their step indices */
  stepGroupMap?: Record<string, number>;
}

interface JsonSchemaProperty {
  type?: string;
  format?: string;
  formatMinimum?: string;
  formatMaximum?: string;
  stepGroup?: number;
  properties?: Record<string, JsonSchemaProperty>;
  [key: string]: unknown;
}

interface FormJsonSchema {
  type?: string;
  properties?: Record<string, JsonSchemaProperty>;
  required?: string[];
  steps?: FormStep[];
  stepGroupMap?: Record<string, number>;
  [key: string]: unknown;
}

// ============================================================================
// ZOD → JSON SCHEMA (for storage/transport)
// ============================================================================

/**
 * Convert a Zod schema to JSON Schema with proper handling for:
 * - z.date() → { type: "string", format: "date-time" }
 * - Date min/max constraints → formatMinimum/formatMaximum
 * - Steps metadata (if provided via schema.meta() or explicit metadata param)
 * 
 * @param schema - The Zod schema to convert
 * @param metadata - Optional explicit metadata to include (overrides schema meta)
 */
export function zodToFormSchema<T extends z.ZodType>(
  schema: T,
  metadata?: FormSchemaMetadata
): FormJsonSchema {
  const jsonSchema = z.toJSONSchema(schema, {
    unrepresentable: "any",
    override: (ctx) => {
      const def = (ctx.zodSchema as any)?._zod?.def;
      if (def?.type === "date") {
        ctx.jsonSchema.type = "string";
        ctx.jsonSchema.format = "date-time";

        // Preserve min/max date constraints
        // In Zod v4, these are available as minDate/maxDate on the schema object
        const zodSchema = ctx.zodSchema as any;
        if (zodSchema.minDate) {
          ctx.jsonSchema.formatMinimum = zodSchema.minDate;
        }
        if (zodSchema.maxDate) {
          ctx.jsonSchema.formatMaximum = zodSchema.maxDate;
        }
      }
    },
  }) as FormJsonSchema;

  // If explicit metadata is provided, use it
  if (metadata?.steps) {
    jsonSchema.steps = metadata.steps;
  }
  if (metadata?.stepGroupMap) {
    jsonSchema.stepGroupMap = metadata.stepGroupMap;
  }

  return jsonSchema;
}

// ============================================================================
// JSON SCHEMA → ZOD (for validation)
// ============================================================================

/**
 * Extract step group map from JSON Schema properties.
 * Looks for stepGroup property on each field.
 */
function extractStepGroupMap(jsonSchema: FormJsonSchema): Record<string, number> {
  const stepGroupMap: Record<string, number> = {};
  const properties = jsonSchema.properties;

  if (!properties) return stepGroupMap;

  for (const [fieldName, fieldSchema] of Object.entries(properties)) {
    if (typeof fieldSchema.stepGroup === "number") {
      stepGroupMap[fieldName] = fieldSchema.stepGroup;
    }
  }

  return stepGroupMap;
}

/**
 * Find date fields with min/max constraints that need validation.
 */
function findDateFieldsWithConstraints(
  jsonSchema: FormJsonSchema
): Record<string, { min?: string; max?: string }> {
  const dateFields: Record<string, { min?: string; max?: string }> = {};
  const properties = jsonSchema.properties;

  if (!properties) return dateFields;

  for (const [key, prop] of Object.entries(properties)) {
    if (prop.type === "string" && prop.format === "date-time") {
      if (prop.formatMinimum || prop.formatMaximum) {
        dateFields[key] = {
          min: prop.formatMinimum,
          max: prop.formatMaximum,
        };
      }
    }
  }

  return dateFields;
}

/**
 * Add date constraint validations to a schema via superRefine.
 */
function addDateValidations(
  schema: z.ZodType,
  dateFieldsWithConstraints: Record<string, { min?: string; max?: string }>
): z.ZodType {
  if (Object.keys(dateFieldsWithConstraints).length === 0) {
    return schema;
  }

  return schema.superRefine((data: any, ctx) => {
    for (const [key, constraints] of Object.entries(dateFieldsWithConstraints)) {
      const value = data[key];
      if (value === undefined || value === null || value === "") continue;

      const dateValue = new Date(value);
      if (isNaN(dateValue.getTime())) {
        ctx.addIssue({
          code: z.ZodIssueCode.custom,
          message: "Invalid date",
          path: [key],
        });
        continue;
      }

      if (constraints.min) {
        const minDate = new Date(constraints.min);
        if (dateValue < minDate) {
          ctx.addIssue({
            code: z.ZodIssueCode.custom,
            message: `Date must be after ${minDate.toLocaleDateString()}`,
            path: [key],
          });
        }
      }

      if (constraints.max) {
        const maxDate = new Date(constraints.max);
        if (dateValue > maxDate) {
          ctx.addIssue({
            code: z.ZodIssueCode.custom,
            message: `Date must be before ${maxDate.toLocaleDateString()}`,
            path: [key],
          });
        }
      }
    }
  });
}

/**
 * Re-attach steps metadata to a Zod schema via .meta().
 * This is necessary because z.fromJSONSchema() doesn't preserve custom properties.
 */
function attachStepsMetadata(
  schema: z.ZodType,
  jsonSchema: FormJsonSchema
): z.ZodType {
  const steps = jsonSchema.steps;
  if (!steps || steps.length === 0) {
    return schema;
  }

  // Get stepGroupMap from either root level or extract from properties
  const stepGroupMap = jsonSchema.stepGroupMap ?? extractStepGroupMap(jsonSchema);

  return schema.meta({
    steps,
    stepGroupMap,
  });
}

/**
 * Convert JSON Schema to Zod schema with proper handling for:
 * - { type: "string", format: "date-time" } → date field (with constraints)
 * - Steps metadata re-attachment (preserved via .meta())
 * - Step group mapping
 * 
 * @param jsonSchema - The JSON Schema to convert
 * @returns A Zod schema ready for validation, with all metadata preserved
 */
export function formSchemaToZod(jsonSchema: FormJsonSchema): z.ZodType {
  // 1. Create base schema from JSON Schema
  let schema = z.fromJSONSchema(jsonSchema as z.core.JSONSchema.JSONSchema);

  // 2. Add date constraint validations
  const dateFieldsWithConstraints = findDateFieldsWithConstraints(jsonSchema);
  schema = addDateValidations(schema, dateFieldsWithConstraints);

  // 3. Re-attach steps metadata so SteppedAutoForm can extract it
  schema = attachStepsMetadata(schema, jsonSchema);

  return schema;
}

// ============================================================================
// UTILITY FUNCTIONS
// ============================================================================

/**
 * Check if a JSON Schema has multi-step configuration.
 */
export function hasSteps(jsonSchema: FormJsonSchema): boolean {
  return Array.isArray(jsonSchema.steps) && jsonSchema.steps.length > 0;
}

/**
 * Get steps from a JSON Schema.
 */
export function getSteps(jsonSchema: FormJsonSchema): FormStep[] {
  return jsonSchema.steps ?? [];
}

/**
 * Get the step group map from a JSON Schema.
 * Returns a map of field names to step indices.
 */
export function getStepGroupMap(jsonSchema: FormJsonSchema): Record<string, number> {
  return jsonSchema.stepGroupMap ?? extractStepGroupMap(jsonSchema);
}
